select *
from t_popupinfo_sub
where PC_PI_KEYNO = #{PC_PI_KEYNO}

mapper.sql:
	from (
		select B.*
			, @ROWNUM:=@ROWNUM+1 as COUNT
		from (
			select *
			from dy_sa2_paper
			order by sa2_keyno
		) B
		where (@ROWNUM:=0)=0

	 		AND			sa2_problem 	=	#{AH_HOMEDIV_C}


	 		AND			sa2_title 			=	#{UI_ID}


	 		AND			DATE_FORMAT(Conn_date,'%Y-%m-%d') 	>=	#{searchBeginDate}



	 		AND			DATE_FORMAT(Conn_date,'%Y-%m-%d') 	<=	#{searchEndDate}


	)AA
	where 1=1




 		AND		COUNT 				LIKE CONCAT( '%',#{item.searchKeyword},'%')					


 		AND		sa2_problem 		LIKE CONCAT( '%',#{item.searchKeyword},'%')					


 		AND		sa2_title			LIKE CONCAT( '%',#{item.searchKeyword},'%')					


 		AND		sa2_date				LIKE CONCAT( '%',#{item.searchKeyword},'%')					


 		AND		sa2_opinion			LIKE CONCAT( '%',#{item.searchKeyword},'%')					


 		AND (
 				COUNT					LIKE CONCAT( '%',#{item.searchKeyword},'%') 	OR
 				sa2_problem 			LIKE CONCAT( '%',#{item.searchKeyword},'%') 	OR
 				sa2_title 				LIKE CONCAT( '%',#{item.searchKeyword},'%') 	OR
 				sa2_date				LIKE CONCAT( '%',#{item.searchKeyword},'%')     OR
 				sa2_opinion				LIKE CONCAT( '%',#{item.searchKeyword},'%') 	

 		)

mapper.select:
    	SELECT	* 

		and sa2_UI_KEYNO = #{SU_UI_KEYNO}


	 		ORDER BY	COUNT ${sortDirect}


	 		ORDER BY	sa2_problem ${sortDirect}


	 		ORDER BY	sa2_title ${sortDirect}


	 		ORDER BY	sa2_date ${sortDirect}


	 		ORDER BY	sa2_opinion ${sortDirect}


	 		ORDER BY 	COUNT DESC



		LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}

      SELECT *
	  from dy_sa_user
	  where SU_UI_KEYNO = #{UI_KEYNO}
	  and SU_SA_AREA = #{area}
	  order by SU_SA_SULBI asc

    select *
	from( 
		SELECT *,
		lag(SU_KEYNO) over(order by SU_SA_SULBI asc) as su_keyno_pre,
		lead(SU_KEYNO) over(order by SU_SA_SULBI asc) as su_keyno_next
		from dy_sa_user
		order by SU_SA_SULBI asc
		)A
	where A.SU_KEYNO = #{SU_KEYNO}

SELECT *
from dy_sa_paper
where sa_keyno = #{sa_keyno}

    SELECT *
	FROM (
	    SELECT *
	    FROM dy_sa2_paper
	    WHERE sa2_su_keyno = #{sa2_keyno}
	    ORDER BY Conn_date DESC
	    LIMIT 2
	) AS recent_data
	ORDER BY Conn_date ASC
	LIMIT 1;

   SELECT *
	FROM (
	   SELECT *, ROW_NUMBER() OVER (ORDER BY Conn_date DESC) AS row_num
	   FROM dy_sa_user a
	   LEFT JOIN dy_sa2_paper b ON a.SU_KEYNO = b.sa2_su_keyno AND a.SU_UI_KEYNO = b.sa2_UI_KEYNO
	   WHERE SU_KEYNO = #{SU_KEYNO} 
	   AND a.SU_UI_KEYNO = #{UI_KEYNO}
	) AS ranked
	WHERE row_num = 2;

SELECT *
from dy_sa2_paper
where sa2_UI_KEYNO = #{UI_KEYNO}
and sa2_su_keyno = #{SU_KEYNO}
order by Conn_date desc
limit 1

