mapper.select:
SELECT * 
FROM dy_sa_paper a 
join dy_sa_user b
on a.sa_sulbi = b.SU_SA_SULBI
where date_format(a.Conn_date, '%Y') =  #{Year}
and date_format(a.Conn_date, '%m') = #{Month}
and b.SU_KEYNO = #{su_keyno}

SELECT *
FROM dy_sa2_paper a
join dy_sa_user b
on a.sa2_title = b.SU_SA_SULBI
where date_format(a.Conn_date, '%Y') =  #{Year}
and date_format(a.Conn_date, '%m') = #{Month}
and b.SU_KEYNO = #{su_keyno}

SELECT sa2_keyno, date_format(a.Conn_date, '%d일') datenum
FROM dy_sa2_paper a 
join dy_sa_user b
on a.sa2_title = b.SU_SA_SULBI
and a.sa2_UI_KEYNO = b.SU_UI_KEYNO 
where date_format(a.Conn_date, '%Y') =  #{Year}
and date_format(a.Conn_date, '%m') = #{Month}
and b.SU_KEYNO = #{su_keyno}

select *
from dy_sa2_paper
where sa2_keyno = #{selectgroup}

select count(*) count
from(
		SELECT sa2_keyno, date_format(a.Conn_date, '%d일') datenum
		FROM dy_sa2_paper a 
		join dy_sa_user b
		on a.sa2_su_keyno = b.SU_KEYNO
		and a.sa2_UI_KEYNO = b.SU_UI_KEYNO
		where date_format(a.Conn_date, '%Y-%m') =  date_format(now() , '%Y-%m')
		and b.SU_KEYNO = #{su_keyno}
	)sa

SELECT a.sa2_meter1KWh AS prewatt
FROM dy_sa2_paper a
JOIN dy_sa_user b ON a.sa2_su_keyno = b.SU_KEYNO

	WHERE date_format(a.Conn_date, '%Y-%m')  < #{formatDate}

AND a.sa2_su_keyno = #{SU_KEYNO}
ORDER BY a.Conn_date DESC
LIMIT 1;

select AA.* from ( SELECT *, COUNT(CASE WHEN YEAR(b.Conn_date) = YEAR(NOW()) AND MONTH(b.Conn_date) = MONTH(NOW()) THEN 1 ELSE NULL END) AS checking, CONCAT(COUNT(CASE WHEN YEAR(b.Conn_date) = YEAR(NOW()) AND MONTH(b.Conn_date) = MONTH(NOW()) THEN 1 ELSE NULL END), '회 / ', a.SU_SA_RG,'회') AS combined_column, a.SU_SA_RG - COUNT(CASE WHEN YEAR(b.Conn_date) = YEAR(NOW()) AND MONTH(b.Conn_date) = MONTH(NOW()) THEN 1 ELSE NULL END) AS checkminus, date_format(MAX(b.Conn_date), '%Y-%m-%d') as preAdminDate FROM dy_sa_user a LEFT JOIN dy_sa2_paper b ON a.SU_KEYNO = b.sa2_su_keyno and (YEAR(b.Conn_date), MONTH(b.Conn_date)) = ( SELECT YEAR(MAX(b2.Conn_date)), MONTH(MAX(b2.Conn_date)) FROM dy_sa2_paper b2 WHERE a.SU_KEYNO = b2.sa2_su_keyno ) WHERE SU_UI_KEYNO = #{SU_UI_KEYNO} GROUP BY a.SU_KEYNO ) AA where 1=1
AND SU_SA_AREA = #{areaSelect}
AND sa2_problem = #{AH_HOMEDIV_C}
AND sa2_title = #{UI_ID}
AND DATE_FORMAT(Conn_date,'%Y-%m-%d') >= #{searchBeginDate}
AND DATE_FORMAT(Conn_date,'%Y-%m-%d') <= #{searchEndDate}
AND SU_SA_SULBI LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND AA.checking LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND SU_SA_AD LIKE CONCAT( '%',#{item.searchKeyword},'%')
AND ( sa2_title LIKE CONCAT( '%',#{item.searchKeyword},'%') OR AA.checking LIKE CONCAT( '%',#{item.searchKeyword},'%') OR SU_SA_AD LIKE CONCAT( '%',#{item.searchKeyword},'%') )
ORDER BY AA.SU_SA_SULBI ${sortDirect}, AA.checkminus
ORDER BY AA.checkminus ${sortDirect}, AA.SU_SA_SULBI
ORDER BY AA.SU_SA_SULBI
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

		SELECT	COUNT(*)
		FROM dy_sa_user
		WHERE SU_UI_KEYNO = #{SU_UI_KEYNO}

 			AND			SU_SA_AREA 	=	#{areaSelect}





	 		AND 	(
		 				SU_SA_SULBI	 			LIKE CONCAT( '%',#{item.searchKeyword},'%') OR
		 				SU_SA_AD				LIKE CONCAT( '%',#{item.searchKeyword},'%') 	
	 				)							




		ORDER BY SU_KEYNO ASC

			LIMIT  	#{recordCountPerPage} OFFSET #{firstIndex}
